function changeType(type) {
	cType = type;
	var types = document.getElementsByClassName('type');
	Array.from(types).forEach((el) => {
		if(el.id === cType) {
			el.setAttribute('fill',getColor(el.id));
		} else {
			el.setAttribute('fill','white');
		}
		setCookie("cType", cType);
	Init();
	});
}

function getColor(type) {
	switch (type) {
		case "C":
		case "Q":
			return "blue";
		case "E":
			//return "purple";
		case "R":
			//return "violet";
		case "P":
			//return "green";
		case "K":
			//return "yellow";
		case "L":
			//return "orange";
		case "A":
			return "blue";
		case "control":
			return "red";
		default:
			return "silver";
	}
}

